@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService

<div class="star-rating">
    <div class="stars">
        @for (int i = 1; i <= 5; i++)
        {
            var starValue = i;
            <span class="star @(GetStarClass(starValue))"
                  @onmouseover="() => hoveredStar = starValue"
                  @onmouseout="() => hoveredStar = 0"
                  @onclick="() => SubmitRating(starValue)">
                @(IsStarFilled(starValue) ? "★" : "☆")
            </span>
        }
    </div>
    <span class="rating-text">@displayRating.ToString("F1") avg (@displayTotalRatings ratings)</span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentRating { get; set; }
    [Parameter] public int TotalRatings { get; set; }

    private int hoveredStar;
    private int selectedStar;
    private double displayRating;
    private int displayTotalRatings;

    protected override void OnParametersSet()
    {
        displayRating = CurrentRating;
        displayTotalRatings = TotalRatings;
    }

    private bool IsStarFilled(int star)
    {
        if (hoveredStar > 0) return star <= hoveredStar;
        if (selectedStar > 0) return star <= selectedStar;
        return star <= Math.Round(displayRating);
    }

    private string GetStarClass(int star)
    {
        return IsStarFilled(star) ? "filled" : "empty";
    }

    private void SubmitRating(int stars)
    {
        selectedStar = stars;
        RecipeService.AddRating(RecipeId, stars);
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            displayRating = recipe.AverageRating;
            displayTotalRatings = recipe.TotalRatings;
        }
    }
}

