    user-select: none;
}

.star.filled {
    color: #ffc107;
}

.star.empty {
    color: #ddd;
}

.star:hover {
    transform: scale(1.1);
}

.rating-text {
    font-size: 0.9rem;
    color: #666;
    margin-left: 0.5rem;
}

