@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService
@using System.ComponentModel.DataAnnotations

<PageTitle>Submit Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Recipe submitted successfully!</h4>
        <p>Your recipe "<strong>@submittedTitle</strong>" has been added.</p>
        <a href="recipe/@submittedId" class="btn btn-primary">View Recipe</a>
    </div>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmit" class="mt-3" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Title</label>
            <InputText id="title" class="form-control" @bind-Value="model.Title" />
            <ValidationMessage For="() => model.Title" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="model.Category">
                <option value="">-- Select a category --</option>
                <option value="Breakfast">Breakfast</option>
                <option value="Lunch">Lunch</option>
                <option value="Dinner">Dinner</option>
                <option value="Desserts">Desserts</option>
                <option value="Snacks">Snacks</option>
            </InputSelect>
            <ValidationMessage For="() => model.Category" />
        </div>

        <div class="mb-3">
            <label for="description" class="form-label">Description</label>
            <InputTextArea id="description" class="form-control" rows="3" @bind-Value="model.Description" />
            <ValidationMessage For="() => model.Description" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" class="form-control" rows="5" @bind-Value="model.Ingredients" />
            <ValidationMessage For="() => model.Ingredients" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" class="form-control" rows="5" @bind-Value="model.Steps" />
            <ValidationMessage For="() => model.Steps" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeFormModel model = new();
    private bool submitted;
    private int submittedId;
    private string submittedTitle = "";

    private void HandleSubmit()
    {
        var recipe = new RecipeShare.Models.Recipe
        {
            Title = model.Title,
            Category = model.Category,
            Description = model.Description,
            Ingredients = model.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            Steps = model.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList()
        };

        RecipeService.AddRecipe(recipe);
        submittedId = recipe.Id;
        submittedTitle = recipe.Title;
        submitted = true;
    }

    private class RecipeFormModel
    {
        [Required(ErrorMessage = "Title is required")]
        public string Title { get; set; } = "";

        [Required(ErrorMessage = "Category is required")]
        public string Category { get; set; } = "";

        [Required(ErrorMessage = "Description is required")]
        public string Description { get; set; } = "";

        [Required(ErrorMessage = "Ingredients are required")]
        public string Ingredients { get; set; } = "";

        [Required(ErrorMessage = "Steps are required")]
        public string Steps { get; set; } = "";
    }
}

