@page "/recipes"
@page "/recipes/{CategoryName}"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>@(CategoryName is not null ? $"{CategoryName} Recipes" : "All Recipes") - RecipeShare</PageTitle>

<h1>@(CategoryName is not null ? $"{CategoryName} Recipes" : "All Recipes")</h1>

@if (CategoryName is not null)
{
    <p><a href="recipes">← Back to all recipes</a></p>
}

@if (CategoryName is not null)
{
    var recipes = RecipeService.GetByCategory(CategoryName);
    <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
        @foreach (var recipe in recipes)
        {
            <div class="col">
                <div class="card recipe-card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text">@recipe.Description</p>
                        <p class="card-text"><small class="text-muted">★ @recipe.AverageRating.ToString("F1") avg (@recipe.TotalRatings ratings)</small></p>
                        <a href="recipe/@recipe.Id" class="btn btn-primary btn-sm">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}
else
{
    var allRecipes = RecipeService.GetAll();
    var grouped = allRecipes.GroupBy(r => r.Category);

    @foreach (var group in grouped)
    {
        <h3 class="mt-4 mb-3">@group.Key</h3>
        <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4 mb-4">
            @foreach (var recipe in group)
            {
                <div class="col">
                    <div class="card recipe-card h-100">
                        <div class="card-body">
                            <h5 class="card-title">@recipe.Title</h5>
                            <p class="card-text">@recipe.Description</p>
                            <p class="card-text"><small class="text-muted">★ @recipe.AverageRating.ToString("F1") avg (@recipe.TotalRatings ratings)</small></p>
                            <a href="recipe/@recipe.Id" class="btn btn-primary btn-sm">View Recipe</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
}

@code {
    [Parameter]
    public string? CategoryName { get; set; }
}

@page "/recipe/{Id:int}"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

@if (recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>The recipe you're looking for doesn't exist.</p>
    <a href="recipes">Browse all recipes</a>
}
else
{
    <div class="recipe-detail">
        <h1>@recipe.Title</h1>
        <p class="text-muted">Category: <a href="recipes/@recipe.Category">@recipe.Category</a></p>
        <p class="lead">@recipe.Description</p>

        <h3>Ingredients</h3>
        <ul>
            @foreach (var ingredient in recipe.Ingredients)
            {
                <li>@ingredient</li>
            }
        </ul>

        <h3>Steps</h3>
        <ol>
            @foreach (var step in recipe.Steps)
            {
                <li class="mb-2">@step</li>
            }
        </ol>

        <h3>Rate this Recipe</h3>
        <StarRating RecipeId="@recipe.Id" CurrentRating="@recipe.AverageRating" TotalRatings="@recipe.TotalRatings" />
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private RecipeShare.Models.Recipe? recipe;

    protected override void OnInitialized()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService

<div class="star-rating">
    <div class="stars">
        @for (int i = 1; i <= 5; i++)
        {
            var starValue = i;
            <span class="star @(GetStarClass(starValue))"
                  @onmouseover="() => hoveredStar = starValue"
                  @onmouseout="() => hoveredStar = 0"
                  @onclick="() => SubmitRating(starValue)">
                @(IsStarFilled(starValue) ? "★" : "☆")
            </span>
        }
    </div>
    <span class="rating-text">@displayRating.ToString("F1") avg (@displayTotalRatings ratings)</span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentRating { get; set; }
    [Parameter] public int TotalRatings { get; set; }

    private int hoveredStar;
    private int selectedStar;
    private double displayRating;
    private int displayTotalRatings;

    protected override void OnParametersSet()
    {
        displayRating = CurrentRating;
        displayTotalRatings = TotalRatings;
    }

    private bool IsStarFilled(int star)
    {
        if (hoveredStar > 0) return star <= hoveredStar;
        if (selectedStar > 0) return star <= selectedStar;
        return star <= Math.Round(displayRating);
    }

    private string GetStarClass(int star)
    {
        return IsStarFilled(star) ? "filled" : "empty";
    }

    private void SubmitRating(int stars)
    {
        selectedStar = stars;
        RecipeService.AddRating(RecipeId, stars);
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            displayRating = recipe.AverageRating;
            displayTotalRatings = recipe.TotalRatings;
        }
    }
}

.star-rating {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.stars {
    display: flex;
    gap: 0.1rem;
}

.star {
    font-size: 1.5rem;
    cursor: pointer;
    transition: color 0.15s ease;
    user-select: none;
}

.star.filled {
    color: #ffc107;
}

.star.empty {
    color: #ddd;
}

.star:hover {
    transform: scale(1.1);
}

.rating-text {
    font-size: 0.9rem;
    color: #666;
    margin-left: 0.5rem;
}

@page "/submit"
@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService
@using System.ComponentModel.DataAnnotations

<PageTitle>Submit Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Recipe submitted successfully!</h4>
        <p>Your recipe "<strong>@submittedTitle</strong>" has been added.</p>
        <a href="recipe/@submittedId" class="btn btn-primary">View Recipe</a>
    </div>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmit" class="mt-3" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Title</label>
            <InputText id="title" class="form-control" @bind-Value="model.Title" />
            <ValidationMessage For="() => model.Title" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="model.Category">
                <option value="">-- Select a category --</option>
                <option value="Breakfast">Breakfast</option>
                <option value="Lunch">Lunch</option>
                <option value="Dinner">Dinner</option>
                <option value="Desserts">Desserts</option>
                <option value="Snacks">Snacks</option>
            </InputSelect>
            <ValidationMessage For="() => model.Category" />
        </div>

        <div class="mb-3">
            <label for="description" class="form-label">Description</label>
            <InputTextArea id="description" class="form-control" rows="3" @bind-Value="model.Description" />
            <ValidationMessage For="() => model.Description" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" class="form-control" rows="5" @bind-Value="model.Ingredients" />
            <ValidationMessage For="() => model.Ingredients" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" class="form-control" rows="5" @bind-Value="model.Steps" />
            <ValidationMessage For="() => model.Steps" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeFormModel model = new();
    private bool submitted;
    private int submittedId;
    private string submittedTitle = "";

    private void HandleSubmit()
    {
        var recipe = new RecipeShare.Models.Recipe
        {
            Title = model.Title,
            Category = model.Category,
            Description = model.Description,
            Ingredients = model.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            Steps = model.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList()
        };

        RecipeService.AddRecipe(recipe);
        submittedId = recipe.Id;
        submittedTitle = recipe.Title;
        submitted = true;
    }

    private class RecipeFormModel
    {
        [Required(ErrorMessage = "Title is required")]
        public string Title { get; set; } = "";

        [Required(ErrorMessage = "Category is required")]
        public string Category { get; set; } = "";

        [Required(ErrorMessage = "Description is required")]
        public string Description { get; set; } = "";

        [Required(ErrorMessage = "Ingredients are required")]
        public string Ingredients { get; set; } = "";

        [Required(ErrorMessage = "Steps are required")]
        public string Steps { get; set; } = "";
    }
}

